def brier_score_loss(y_true, y_proba=None, *, sample_weight=None, pos_label=None, y_prob='deprecated'):
    """The `brier_score_loss` function calculates the Brier score loss, which measures the mean squared difference between predicted probabilities and actual binary outcomes. The function supports binary classification and includes error handling for deprecated parameters, input type checking, and label consistency. Inputs include the true labels (`y_true`), predicted probabilities (`y_proba`), optional sample weights, and a parameter to define the positive class label (`pos_label`). The output is a float representing the Brier score loss. Errors are raised for incorrect input types, non-binary classification targets, and probability values outside the [0, 1] range."""
    if y_prob != 'deprecated':
        if y_proba is not None:
            raise ValueError('`y_prob` and `y_proba` cannot be both specified. Please use `y_proba` only as `y_prob` is deprecated.')
        warnings.warn('y_prob was deprecated. Please use ``y_proba`` instead.', FutureWarning)
        y_proba = y_prob

    y_true = column_or_1d(y_true)
    y_proba = column_or_1d(y_proba)
    assert_all_finite(y_true)
    assert_all_finite(y_proba)
    check_consistent_length(y_true, y_proba, sample_weight)

    y_type = type_of_target(y_true, input_name='y_true')
    if y_type != 'binary':
        raise ValueError(f'Only binary classification is supported. The type of the target is {y_type}.')

    if np.any(y_proba < 0) or np.any(y_proba > 1):
        raise ValueError('y_proba has values outside [0, 1].')

    try:
        pos_label = _check_pos_label_consistency(pos_label, y_true)
    except ValueError:
        classes = np.unique(y_true)
        if classes.dtype.kind not in ('O', 'U', 'S'):
            pos_label = classes[-1]
        else:
            raise

    y_true = np.array(y_true == pos_label, int)
    return np.average((y_true - y_proba) ** 2, weights=sample_weight)

